const DATA_DIR = join(__dirname, '..', 'data');
const DAILY_DIR = join(DATA_DIR, 'daily-reports');
if (!existsSync(DAILY_DIR)) mkdirSync(DAILY_DIR, { recursive: true });

const mode = process.argv[2] || 'light';

function run(cmd) {
  console.log(`  → ${cmd}`);
  try {
    execSync(cmd, { cwd: SCRIPTS_DIR, stdio: 'inherit', timeout: 300000 });
    return true;
  } catch (err) {
    console.error(`  ✗ 失败: ${err.message}`);
    return false;
  }
}

console.log(`\n🔍 小满客户巡检 — ${new Date().toLocaleString('zh-CN')}`);
