  process.exit(0);
}

const diffResult = run('node diff.mjs');
if (!diffResult) {
  console.error('对比失败，终止');
  process.exit(1);
}

// Step 3: 生成每日报告摘要（供CC读取）
const diffDir = join(DATA_DIR, 'diffs');
const diffFiles = readdirSync(diffDir)
  .filter(f => f.startsWith('diff_') && f.endsWith('.json'))
  .sort()
  .reverse();

if (diffFiles.length > 0) {
  const diffData = JSON.parse(readFileSync(join(diffDir, diffFiles[0]), 'utf-8'));

  const dailyReport = {
    generatedAt: new Date().toISOString(),
    status: 'ok',
    summary: diffData.summary,
    P0: diffData.urgency.P0.map(c => ({
      name: c.name,
      categoryId: c.classification.categoryId,
      tier: c.classification.tier,
      reason: c.classification.reason,
      lastMessage: c.lastMessageSnippet?.substring(0, 100),
      isUnread: c.isUnread
    })),
    P1: diffData.urgency.P1.map(c => ({
      name: c.name,
      categoryId: c.classification.categoryId,
      reason: c.classification.reason
    }))
  };

  const now = new Date();
  const dateStr = now.toISOString().substring(0, 10);
  const reportPath = join(DAILY_DIR, `daily_${dateStr}.json`);
  writeFileSync(reportPath, JSON.stringify(dailyReport, null, 2));

  console.log(`\n📊 每日报告已生成: daily_${dateStr}.json`);
  console.log(`   P0待处理: ${dailyReport.P0.length}人`);
  console.log(`   P1待处理: ${dailyReport.P1.length}人`);

