    });
    md += '\n';
  }

  // ==================== 操作指南 ====================
  md += `---

## 📋 操作指南

1. **P0 客户**：复制上方"CC 分析提示"发给 Claude Code，获取完整五步分析+话术
2. **P1 客户**：在"每日跟进"时间段内逐个处理
3. **P2/P3 客户**：每周一运行 \`node generate-weekly-report.mjs\` 获取批量激活方案

---

*本报告由 AI外贸顾问系统自动生成 | ${generatedAt}*
`;

  return md;
}

// ============================================================
// 主入口
// ============================================================
function main() {
  const args = process.argv.slice(2);

  let reportPath;
  if (args.length > 0) {
    reportPath = join(DAILY_DIR, `daily_${args[0]}.json`);
  } else {
    // 找最新的daily报告
    const files = readdirSync(DAILY_DIR)
      .filter(f => f.startsWith('daily_') && f.endsWith('.json'))
      .sort()
      .reverse();
    if (files.length === 0) {
      console.error('未找到每日报告。请先运行 node daily-check.mjs');
      process.exit(1);
    }
    reportPath = join(DAILY_DIR, files[0]);
  }

  if (!existsSync(reportPath)) {
    console.error(`报告不存在: ${reportPath}`);
    process.exit(1);
  }

  console.log('[report] 读取每日数据...');
  const dailyData = JSON.parse(readFileSync(reportPath, 'utf-8'));

  const markdown = generateMarkdown(dailyData);
  const dateStr = dailyData.generatedAt.substring(0, 10);
  const outputPath = join(REPORTS_DIR, `每日战报_${dateStr}.md`);

  writeFileSync(outputPath, markdown);
  console.log(`[report] 每日战报已生成: ${outputPath}`);
  console.log(`[report] P0: ${dailyData.P0?.length || 0}人 | P1: ${dailyData.P1?.length || 0}人`);

  // 也打印到终端
  console.log('\n' + markdown);
}

main();

