      h2('第一步：客户画像'),
      make2ColTable([
        ['国家/区域', '赞比亚（要求发货到加纳，可能在两地都有业务）'],
        ['角色判断', '个体店主 / 小批发商（5件试单，非品牌商）'],
        ['核心意图', '试单询价——5件童装，先测运费和总成本'],
        ['采购阶段', '已报价（USD + RMB 双币种）→ 客户沉默8天'],
        ['沟通语言', '英语'],
        ['关键信号', '客户4月3日第一次接触后消失17天，4月20日主动回来——有意向，不是随便问问'],
      ]),

      // Step 2
      h2('第二步：卡点诊断'),
      boldP('核心卡点：运费碾压产品价值，客户无法接受。'),
      p('逐条对话还原：'),
      p('1. 客户问"If I buy 5 pieces how much will each cost" → 我们报 $4.20/pc，5件共$21'),
      p('2. 客户紧接着问"how much is the shipping cost" → 我们报 $66 DAP to Ghana'),
