      new Table({
        width: { size: 100, type: WidthType.PERCENTAGE },
        rows: [
          new TableRow({ children: [cell(''), cell('方案A（常规：等客户回复）', { bold: true }), cell('方案B（推荐：主动破解运费困局）', { bold: true })] }),
          new TableRow({ children: [cell('策略', { bold: true }), cell('等客户自己做决定'), cell('主动提供两个降运费方案：FOB给货代 or 加件摊薄运费')] }),
          new TableRow({ children: [cell('优势', { bold: true }), cell('省事'), cell('精准击中客户沉默的真实原因，展示你在帮她省钱')] }),
          new TableRow({ children: [cell('风险', { bold: true }), cell('客户可能已找其他供应商'), cell('如果客户坚持要DDP全包价，我们没有更好的运费方案')] }),
        ]
