1	/**
2	 * 小满CRM — 聊天记录抓取器 v2
3	 *
4	 * 用法: node scraper.mjs
5	 * 前置条件: Chrome 端口9222已开启，小满已登录并在TM消息页
6	 */
7	
8	import { chromium } from 'playwright';
9	import { writeFileSync } from 'fs';
10	import { join, dirname } from 'path';
11	import { fileURLToPath } from 'url';
12	import { saveCustomerImages } from './image-utils.mjs';
13	
14	const __dirname = dirname(fileURLToPath(import.meta.url));
15	const DATA_DIR = join(__dirname, '..');
16	const CDP_URL = 'http://127.0.0.1:9222';
17	
18	async function connect() {
19	  const browser = await chromium.connectOverCDP(CDP_URL);
20	  const ctx = browser.contexts()[0];
21	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
22	  if (!page) throw new Error('未找到小满页面');
23	  const talkFrame = page.frames()[1];
24	  if (!talkFrame) throw new Error('未找到聊天 iframe');
25	  return { browser, ctx, page, talkFrame };
26	}
27	
28	/**
29	 * 提取会话列表
30	 */
31	async function getConversationList(frame) {
32	  return frame.evaluate(() => {
33	    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
34	      const text = el.textContent || '';
35	      // Extract name from .contact-right (avoids avatar initial prefix issue)
36	      const nameEl = el.querySelector('.contact-right');
37	      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
38	      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
39	      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
40	
41	      const isSelected = el.classList.contains('selected');
42	      const isUnread = text.includes('[未读]');
43	      const lastMsg = nameText.replace(/^.+?\d{2,4}[-:\/]\d{1,2}[-:\/]?\d{0,2}\s*/, '').replace(/\[(未读|已读)\]\s*/, '').trim();
44	
45	      return { name, isUnread, isSelected, lastMessage: lastMsg.substring(0, 200) };
46	    });
47	  });
48	}
49	
50	/**
51	 * 滚动会话列表到底部以确保所有项都在DOM中
52	 */
53	async function scrollConversationList(frame) {
54	  await frame.evaluate(() => {
55	    const container = document.querySelector('.seller-conversation-list') ||
56	      document.querySelector('.conversation-list-content') ||
57	      document.querySelector('.im-conversation-list-container');
58	    if (container) {
59	      container.scrollTop = container.scrollHeight;
60	    }
61	  });
62	  await new Promise(r => setTimeout(r, 500));
63	}
64	
65	/**
66	 * 获取当前已渲染的消息（不含虚拟滚动未加载的旧消息）
67	 */
68	async function getRenderedMessages(frame) {
69	  return frame.evaluate(() => {
70	    const messages = [];
71	    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
72	
73	    wrappers.forEach((wrapper, index) => {
74	      const isLeft = wrapper.classList.contains('item-left');
75	      const isRight = wrapper.classList.contains('item-right');
76	      const isSystem = wrapper.hasAttribute('data-exp') && wrapper.getAttribute('data-exp') === 'sysmsg';
77	
78	      const textEl = wrapper.querySelector('.session-rich-content.text');
79	      const cardEl = wrapper.querySelector('.session-rich-content.card');
80	      const securityEl = wrapper.querySelector('.session-security');
81	      const avatarEl = wrapper.querySelector('.session-avatar.head-portrait.messenger');
82	      const autoReply = wrapper.querySelector('.session-rich-content')?.textContent || '';
83	
84	      // Skip security notices
85	      if (securityEl) return;
86	
87	      // Determine message type
88	      let messageType = 'text';
89	      if (isSystem) messageType = 'system';
90	      else if (cardEl) messageType = 'card';
91	
92	      const contentEl = textEl || cardEl;
93	      let content = contentEl ? contentEl.textContent.trim() : '';
94	
95	      // Clean up content - remove translation artifacts
96	      content = content
97	        .replace(/翻译中…反馈$/, '')
98	        .replace(/由阿里翻译提供反馈$/, '')
99	        .replace(/阿里国际Marco大模型翻译反馈$/, '')
100	        .replace(/由阿里翻译提供$/, '')
101	        .trim();
102	
103	      // Extract timestamp from p.item-base-info span:last-child
104	      const timeEl = wrapper.querySelector('p.item-base-info span:last-child');
105	      const timestamp = timeEl ? (timeEl.textContent || '').trim() : null;
106	
107	      // Extract sender name
108	      const nameEl = wrapper.querySelector('p.item-base-info span.name');
109	      const sender = nameEl ? (nameEl.textContent || '').trim() : (avatarEl ? (avatarEl.textContent || '').trim() : '');
110	
111	      // Extract emojis from img.emotion elements
112	      const emotionEls = wrapper.querySelectorAll('img.emotion');
113	      const emojis = Array.from(emotionEls).map(img => img.alt || img.src || '').filter(Boolean);
114	
115	      // Detect content images (non-emotion, non-smiley)
116	      const contentImgs = wrapper.querySelectorAll('img');
117	      const hasImages = Array.from(contentImgs).some(img => {
118	        if (img.classList.contains('emotion')) return false;
119	        const s = img.src || '';
120	        if (!s.startsWith('http')) return false;
121	        if (s.includes('atmgateway-client.alibaba.com/smily')) return false;
122	        if (s.includes('clouddisk.alibaba.com')) return false;
123	        if (/tps-(48|60|72|80)-\d+\.(png|webp)/.test(s)) return false;
124	        return true;
125	      });
126	
127	      // Detect file/cloud disk links (both <a> and <img> sources)
128	      const fileLinks = [];
129	      wrapper.querySelectorAll('a').forEach(a => {
130	        const href = a.href || '';
131	        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
132	          fileLinks.push({ url: href, name: (a.textContent || '').trim() || (a.title || '') });
133	        }
134	      });
135	      // Also check img src for cloud disk files
136	      wrapper.querySelectorAll('img').forEach(img => {
137	        const s = img.src || '';
138	        if (s.includes('clouddisk.alibaba.com') && !fileLinks.some(f => f.url === s)) {
139	          fileLinks.push({ url: s, name: (img.alt || img.title || '') });
140	        }
141	      });
142	
143	      // Auto-detect message type refinement
144	      if (!isSystem && !cardEl) {
145	        if (fileLinks.length > 0 && !content) {
146	          messageType = 'file';
147	        } else if (hasImages && !content) {
148	          messageType = 'image';
149	        }
150	      }
151	
152	      // Extract card structured data if available
153	      let cardData = null;
154	      if (cardEl) {
155	        const expinfo = cardEl.getAttribute('data-expinfo');
156	        if (expinfo) {
157	          try { cardData = JSON.parse(expinfo); } catch (e) { /* ignore parse errors */ }
158	        }
159	        const cardImg = cardEl.querySelector('img');
160	        if (cardImg && cardImg.src && cardImg.src.startsWith('http')) {
161	          if (!cardData) cardData = {};
162	          cardData.imageUrl = cardImg.src;
163	        }
164	      }
165	
166	      messages.push({
167	        index,
168	        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
169	        content,
170	        messageType,
171	        timestamp,
172	        sender: sender || undefined,
173	        isCard: !!cardEl,
174	        cardData,
175	        emojis: emojis.length > 0 ? emojis : undefined,
176	        hasImages,
177	        fileLinks: fileLinks.length > 0 ? fileLinks : undefined,
178	        isAutoReply: autoReply.includes('自动接待发送') || autoReply.includes('去优化'),
179	        isSystem,
180	      });
181	    });
182	
183	    return messages;
184	  });
185	}
186	
187	/**
188	 * 滚动聊天区域加载所有历史消息（虚拟滚动）
189	 * Returns the scroll container selector used
190	 */
191	async function scrollChatToLoadAll(frame, { maxScrolls = 60, stableThreshold = 3 } = {}) {
192	  const containerInfo = await frame.evaluate(() => {
193	    // Try common scroll container selectors
194	    const selectors = [
195	      '.message-list-container',
196	      '.chat-list',
197	      '.im-chat-list',
198	      '.message-list',
199	      '[class*="message-list"]',
200	      '[class*="chat-list"]',
201	      '[class*="chat-content"]',
202	      '.session-message-list-wrapper',
203	    ];
204	    for (const sel of selectors) {
205	      const el = document.querySelector(sel);
206	      if (el && el.scrollHeight > el.clientHeight) {
207	        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
208	      }
209	    }
210	    // Fallback: find any scrollable element containing messages
211	    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
212	    if (wrappers.length > 0) {
213	      let el = wrappers[0].parentElement;
214	      while (el) {
215	        if (el.scrollHeight > el.clientHeight) {
216	          return { selector: null, found: true, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
217	        }
218	        el = el.parentElement;
219	      }
220	    }
221	    return null;
222	  });
223	
224	  if (!containerInfo) {
225	    console.log('   ⚠️ 未找到可滚动容器，使用当前渲染消息');
226	    return 0;
227	  }
228	
229	  console.log(`   📜 滚动加载历史消息... (容器: ${containerInfo.selector || '自动检测'})`);
230	
231	  let prevCount = 0;
232	  let stableCount = 0;
